VALUES
  ('policepromo-8b7f1efc-moex-00069', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-111-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '下列何者非屬行政機關？', '["臺中市政府衛生局", "衛生福利部中央健康保險署", "臺北市政府警察局中正一分局介壽路派出所", "內政部警政署國道公路警察局"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:26+00:00", "source_pdf_sha1": "cad2635c5595", "answer_pdf_sha1": "e2e4f43c2655", "source_family": "moex-gov-tw", "moex": {"exam_code": "111170", "c": "101", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "111", "exam_name": "111年警察人員升官等考試、111年交通事業郵政人員升資考試、111年交通事業公路人員升資考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('policepromo-8b7f1efc-moex-00070', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-111-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '依照現行法規定，關於行政機關管轄之敘述，下列何者正確？', '["同一事件，數行政機關依法均有管轄權時，應由受理在先之機關管轄；不能分別受理之先後者，由 其共同上級機關指定管轄", "人民就其依法規申請之事件，發生數行政機關於管轄權有爭議時，得向共同上級機關申請指定管轄， 受理申請之機關應自請求到達之日起十五日內決定之", "人民對行政機關所為指定管轄之決定，得向其上級機關聲明不服", "行政機關因法規或事實之變更而喪失管轄權時，應將案件移送有管轄權之機關，並通知當事人。但 經當事人及有管轄權機關之同意，亦得由原管轄機關繼續處理該案件"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:26+00:00", "source_pdf_sha1": "cad2635c5595", "answer_pdf_sha1": "e2e4f43c2655", "source_family": "moex-gov-tw", "moex": {"exam_code": "111170", "c": "101", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "111", "exam_name": "111年警察人員升官等考試、111年交通事業郵政人員升資考試、111年交通事業公路人員升資考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('policepromo-8b7f1efc-moex-00071', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-111-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '行政機關發現行政處分違反事件管轄權規定時，下列敘述何者錯誤？', '["若已作成之行政處分違反土地管轄規定者，均為無效", "若已作成之行政處分未經授權而違背法規關於專屬管轄規定者，均為無效", "若已作成之行政處分缺乏事務權限者，均為無效", "行政機關對事件管轄權之有無，應依職權調查；其認無管轄權者，應即移送有管轄權之機關，並通 知當事人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:26+00:00", "source_pdf_sha1": "cad2635c5595", "answer_pdf_sha1": "e2e4f43c2655", "source_family": "moex-gov-tw", "moex": {"exam_code": "111170", "c": "101", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "111", "exam_name": "111年警察人員升官等考試、111年交通事業郵政人員升資考試、111年交通事業公路人員升資考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('policepromo-8b7f1efc-moex-00072', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-111-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '依現行法規定，就違反地方自治事項之行政業務者，縣（市）規章可規定之不利處分，不包含下列何者？', '["斷水斷電", "新臺幣10萬元以下罰鍰", "勒令停工", "吊扣執照"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:26+00:00", "source_pdf_sha1": "cad2635c5595", "answer_pdf_sha1": "e2e4f43c2655", "source_family": "moex-gov-tw", "moex": {"exam_code": "111170", "c": "101", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "111", "exam_name": "111年警察人員升官等考試、111年交通事業郵政人員升資考試、111年交通事業公路人員升資考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('policepromo-8b7f1efc-moex-00073', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-111-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '下列何者非屬公務員服務法上之公務員？', '["兼任系所主管之國立大學教師", "中央研究院院長", "立法委員", "陸海空軍軍官士官"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:26+00:00", "source_pdf_sha1": "cad2635c5595", "answer_pdf_sha1": "e2e4f43c2655", "source_family": "moex-gov-tw", "moex": {"exam_code": "111170", "c": "101", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "111", "exam_name": "111年警察人員升官等考試、111年交通事業郵政人員升資考試、111年交通事業公路人員升資考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('policepromo-8b7f1efc-moex-00074', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-111-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '關於公務人員停職之敘述，下列何者錯誤？', '["公務人員於停職期間，仍具公務人員身分", "公務人員於停職期間，仍得執行職務", "經依法停職之公務人員，於停職事由消滅後三個月內，得申請復職", "經依法停職之公務人員，於停職事由消滅後三個月內，未申請復職，且接到服務機關或其上級機關人 事單位查催通知之日起三十日內仍未申請復職者，除有不可歸責於該公務人員之事由外，視為辭職"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:26+00:00", "source_pdf_sha1": "cad2635c5595", "answer_pdf_sha1": "e2e4f43c2655", "source_family": "moex-gov-tw", "moex": {"exam_code": "111170", "c": "101", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "111", "exam_name": "111年警察人員升官等考試、111年交通事業郵政人員升資考試、111年交通事業公路人員升資考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('policepromo-8b7f1efc-moex-00075', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-111-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '依現行法規定，關於公務員懲戒處分之敘述，下列何者正確？', '["曾經免除職務，或經撤職且於一定時間停止任用者，均不得再任公務員", "對於已退休（職、伍）或其他原因已離職之公務員，就其任職期間之違法行為，不溯及懲戒", "公務員經依法移送懲戒，或經主管機關送請監察院審查者，在不受懲戒、免議、不受理判決確定、 懲戒處分生效或審查結束前，不得資遣或申請退休、退伍", "休職、減俸、降級處分於政務人員不適用之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:26+00:00", "source_pdf_sha1": "cad2635c5595", "answer_pdf_sha1": "e2e4f43c2655", "source_family": "moex-gov-tw", "moex": {"exam_code": "111170", "c": "101", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "111", "exam_name": "111年警察人員升官等考試、111年交通事業郵政人員升資考試、111年交通事業公路人員升資考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('policepromo-8b7f1efc-moex-00076', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-111-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '關於訂定法規命令之敘述，下列何者正確？', '["行政機關訂定法規命令，縱屬有關軍事、外交或其他重大事項而涉及國家機密或安全，亦必須遵守 行政程序法所定程序", "法規命令之訂定，亦可由人民或團體提議為之", "行政機關訂定法規命令時，應舉行聽證", "立法者授權行政機關為補充法規範內容所為「公告」，其性質均為行政規則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:26+00:00", "source_pdf_sha1": "cad2635c5595", "answer_pdf_sha1": "e2e4f43c2655", "source_family": "moex-gov-tw", "moex": {"exam_code": "111170", "c": "101", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "111", "exam_name": "111年警察人員升官等考試、111年交通事業郵政人員升資考試、111年交通事業公路人員升資考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('policepromo-8b7f1efc-moex-00077', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-111-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '下列何者不具法規性質？', '["中華電信股份有限公司行動寬頻業務營業規章", "高雄市地籍參考圖核發及收費辦法", "定期通盤檢討對原都市計畫之主要計畫或細部計畫所作必要變更，其內容尚未直接限制一定區域內 特定人或可得確定多數人之權益或增加負擔者", "全民健康保險投保金額分級表"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:26+00:00", "source_pdf_sha1": "cad2635c5595", "answer_pdf_sha1": "e2e4f43c2655", "source_family": "moex-gov-tw", "moex": {"exam_code": "111170", "c": "101", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "111", "exam_name": "111年警察人員升官等考試、111年交通事業郵政人員升資考試、111年交通事業公路人員升資考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('policepromo-8b7f1efc-moex-00078', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-111-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '內政部移民署受理外國人甲申請永久居留案件後，已逾半年仍未作出准駁決定，亦未通知申請人延長 處理期間。下列敘述何者錯誤？', '["除法規另有規定外，內政部移民署至遲應在四個月內處理終結該申請案件", "甲向內政部提起訴願，請求內政部移民署應於一定期限前作出准駁決定", "甲係基於法規之申請，如以掛號郵寄方式向行政機關提出，以交郵當日之郵戳為準", "甲應以內政部移民署為被告機關逕向臺北高等行政法院提起課以義務訴訟，請求內政部移民署應於 一定期限前作出准駁決定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:26+00:00", "source_pdf_sha1": "cad2635c5595", "answer_pdf_sha1": "e2e4f43c2655", "source_family": "moex-gov-tw", "moex": {"exam_code": "111170", "c": "101", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "111", "exam_name": "111年警察人員升官等考試、111年交通事業郵政人員升資考試、111年交通事業公路人員升資考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL)
